parameters.functionCode:
return items.map(item => {
  const body = item.json || {};
  const raw = body.detail || body;
  const source = (body.source || raw.source || '').toString().toLowerCase();
  const alert = raw.alert || raw.finding || raw;

  const normalized = {
    alert_id: alert.id || alert.findingId || alert.id || alert.uuid || null,
    source: source.includes('wiz') ? 'Wiz' : source.includes('guardduty') ? 'GuardDuty' : (body.source || raw.source || 'Unknown'),
    severity: alert.severity || alert.severityLabel || alert.severityScore || alert.riskScore || null,
    region: alert.region || raw.region || raw.awsRegion || alert.awsRegion || null,
    description: alert.description || alert.title || alert.summary || raw.description || null,
    timestamp: alert.createdAt || alert.eventTime || alert.updatedAt || raw.timestamp || new Date().toISOString(),
    original_alert: raw,
    resource_type: null,
    resource_arn: null,
    resource_name: null
  };

  const resource = alert.resource || raw.resource || alert.awsEntity || alert.resourceDetails || {};
  if (resource) {
    normalized.resource_type = resource.type || resource.resourceType || resource.kind || resource.awsResourceType || '';
    normalized.resource_arn = resource.arn || resource.resourceArn || resource.awsArn || resource.awsResourceArn || null;
    normalized.resource_name = resource.name || resource.resourceName || resource.bucketName || resource.instanceId || null;
  }

  if (!normalized.resource_arn && normalized.resource_type && normalized.resource_type.toLowerCase().includes('s3')) {
    normalized.resource_arn = alert.bucketArn || alert.bucketName ? `arn:aws:s3:::${alert.bucketName || resource.bucketName}` : null;
  }

  if (!normalized.resource_type && normalized.resource_arn) {
    if (normalized.resource_arn.includes('s3:::')) normalized.resource_type = 'S3';
    else if (normalized.resource_arn.includes('ec2:instance')) normalized.resource_type = 'EC2';
    else if (normalized.resource_arn.includes(':iam::')) normalized.resource_type = 'IAM';
  }

  if (!normalized.resource_name && normalized.resource_arn && normalized.resource_arn.includes('s3:::')) {
    normalized.resource_name = normalized.resource_arn.split('arn:aws:s3:::')[1];
  }

  return { json: normalized };
});

return items.map(item => {
  const data = item.json || {};
  const severity = parseFloat(data.severity) || 0;
  const isS3 = (data.resource_type || '').toString().toLowerCase().includes('s3');
  const score = Math.min(100, Math.round((severity || 0) * 12 + (isS3 ? 20 : 0)));
  const autoContain = isS3 && score >= 40;
  const decision = autoContain ? 'contain' : score >= 25 ? 'review' : 'monitor';
  return {
    json: {
      ...data,
      risk_score: score,
      decision,
      autoContain,
      containment_action: autoContain ? 'block_public_and_deny_bucket_policy' : null,
      notification_subject: autoContain ? `AWS Compromise Containment Required for ${data.resource_name || data.resource_arn}` : `AWS Alert - ${data.alert_id || 'Unknown'}`
    }
  };
});

